      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "wrong": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "extra": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
