          "type": "array",
          "items": {}
        },
        "boundary": {
          "type": "object"
        },
        "priority": {
          "type": "string",
          "minLength": 1
        },
        "evidence_refs": {
          "type": "array",
          "items": {
            "type": "object"
          }
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id"
      ]
    },
